CODE_CRITIQUE_SYSTEM = """
You are a code reviewer. Critique code on these dimensions only:
1. Logic errors: does the code do what the comment/docstring says?
2. Edge cases: does it handle empty input, None, zero, negative numbers, or maximum values?
3. Off-by-one: are array indices and loop bounds correct?
4. Type safety: are type assumptions documented or enforced?

Do NOT comment on style, naming, or performance unless they cause correctness bugs.

Output format:
{
  "issues": [
    {"dimension": "...", "line": "...", "description": "...", "fix": "..."}
  ],
  "verdict": "pass" | "needs_revision"
}
If no issues: {"issues": [], "verdict": "pass"}
"""

import anthropic, json

client = anthropic.Anthropic()

def critique_code(code: str) -> dict:
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=512,
        system=CODE_CRITIQUE_SYSTEM,
        messages=[{"role": "user", "content": f"Review this code:\n\n{code}"}],
    )
    try:
        return json.loads(resp.content[0].text)
    except json.JSONDecodeError:
        return {"issues": [], "verdict": "pass"}

code_to_review = """
def find_max(numbers: list) -> int:
    max_val = 0
    for n in numbers:
        if n > max_val:
            max_val = n
    return max_val
"""

result = critique_code(code_to_review)
print(result)
# Issues: max_val=0 fails for all-negative lists (should be float('-inf') or numbers[0])
# Edge cases: empty list raises IndexError or returns 0 (wrong)

import anthropic
import json

client = anthropic.Anthropic()

AGENT_WITH_CRITIQUE_SYSTEM = """
You are a research assistant. Solve questions step by step.

Process:
1. Research using the search tool.
2. When you have gathered enough information, call draft_answer with your answer.
3. The system will critique your draft. If issues are found, revise and call draft_answer again.
4. When the critique passes, call task_complete with your final answer.

Rules:
- Call draft_answer at most twice — if it fails twice, call task_complete with the best you have.
- Call task_failed if you cannot find any relevant information.
"""

def search(query: str) -> str:
    stubs = {
        "paris capital": '{"ok": true, "city": "Paris", "country": "France", "is_capital": true}',
        "paris population": '{"ok": true, "city": "Paris", "population": 2161000, "area_km2": 105}',
    }
    for k, v in stubs.items():
        if k in query.lower():
            return v
    return json.dumps({"ok": False, "message": "No results."})

DRAFT_CRITIQUE_SYSTEM = """
You evaluate draft answers for factual accuracy and completeness.
Given a question and a draft answer, return JSON:
{
  "pass": true or false,
  "issues": ["issue 1", "issue 2"],
  "suggested_fix": "..." or null
}
Be strict. If the answer contains any factual error, set pass=false.
"""

def run_draft_critique(question: str, draft: str) -> dict:
    resp = client.messages.create(
        model="claude-haiku-4-5-20251001",
        max_tokens=256,
        system=DRAFT_CRITIQUE_SYSTEM,
        messages=[{"role": "user", "content": f"Question: {question}\nDraft: {draft}"}],
    )
    try:
        return json.loads(resp.content[0].text)
    except json.JSONDecodeError:
        return {"pass": True, "issues": [], "suggested_fix": None}

TOOLS = [
    {"name": "search", "description": "Search for factual information.",
     "input_schema": {"type": "object", "properties": {"query": {"type": "string"}}, "required": ["query"]}},
    {"name": "draft_answer", "description": "Submit a draft answer for critique.",
     "input_schema": {"type": "object", "properties": {"answer": {"type": "string"}}, "required": ["answer"]}},
    {"name": "task_complete", "description": "Submit the final, verified answer.",
     "input_schema": {"type": "object", "properties": {"answer": {"type": "string"}}, "required": ["answer"]}},
    {"name": "task_failed", "description": "Call when the question cannot be answered.",
     "input_schema": {"type": "object", "properties": {"reason": {"type": "string"}}, "required": ["reason"]}},
]
DISPATCH = {"search": search}

def run_agent_with_critique_gate(user_question: str) -> dict:
    messages = [{"role": "user", "content": user_question}]
    drafts_used = 0
    max_drafts = 2

    for _ in range(12):
        resp = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=512,
            system=AGENT_WITH_CRITIQUE_SYSTEM,
            tools=TOOLS,
            messages=messages,
        )
        messages.append({"role": "assistant", "content": resp.content})
        tool_calls = [b for b in resp.content if b.type == "tool_use"]

        for block in tool_calls:
            if block.name == "task_complete":
                return {"status": "complete", "answer": block.input["answer"]}
            if block.name == "task_failed":
                return {"status": "failed", "reason": block.input["reason"]}

        if not tool_calls:
            break

        results = []
        for block in tool_calls:
            if block.name == "draft_answer":
                drafts_used += 1
                critique = run_draft_critique(user_question, block.input["answer"])
                if critique["pass"] or drafts_used >= max_drafts:
                    # Critique passed or out of draft attempts — use this answer
                    result = json.dumps({
                        "critique_passed": critique["pass"],
                        "instruction": "The critique passed. Call task_complete with this answer now.",
                        "answer": block.input["answer"],
                    })
                else:
                    # Critique failed — give feedback for revision
                    result = json.dumps({
                        "critique_passed": False,
                        "issues": critique["issues"],
                        "suggested_fix": critique.get("suggested_fix"),
                        "instruction": "Revise your answer addressing the issues above, then call draft_answer again.",
                    })
            else:
                fn = DISPATCH.get(block.name)
                result = fn(**block.input) if fn else json.dumps({"error": "Unknown"})
            results.append({"type": "tool_result", "tool_use_id": block.id, "content": result})
        messages.append({"role": "user", "content": results})

    return {"status": "incomplete"}

outcome = run_agent_with_critique_gate("What is the capital and population of Paris?")
print(outcome)
